    v = v + i - 2;
  } else {
    v = v + i - 4;
  }
  i = i + 1;
  p = p + 1;
}
print v;

// even-odd parity checker with a parity count
let n = 7;
if n % 2 == 0 {
  let even = true;
  let count = 0;
  let mod = n;
  while mod != 0 {
    mod = mod - 1;
    count = count + 1;
  }
  print even;
  print count;
} else if n % 2 != 0 {
  let odd = true;
  let count = 0;
  let mod = n;
  while mod != 0 {
    mod = mod + 1;
    count = count + 1;
  }
  print odd;
  print count;
} else {
  print false;
}

